import{_ as a,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Records & Record Batches","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/records.md","filePath":"how-to/records.md"}'),i={name:"how-to/records.md"};function l(s,e,h,c,n,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="records-record-batches" tabindex="-1">Records &amp; Record Batches <a class="header-anchor" href="#records-record-batches" aria-label="Permalink to &quot;Records &amp; Record Batches&quot;">​</a></h1><p>A <strong>record batch</strong> is a group of saved result rows tied to one event and date. It gives you a clean way to inspect what was saved together.</p><blockquote><p>Screenshot placeholder: records-list.png</p></blockquote><h2 id="where-record-batches-come-from" tabindex="-1">Where record batches come from <a class="header-anchor" href="#where-record-batches-come-from" aria-label="Permalink to &quot;Where record batches come from&quot;">​</a></h2><p>Batches can come from:</p><ul><li>manual input</li><li>screenshot imports</li><li>spreadsheet imports</li></ul><p>They are useful when you want to trace saved rows back to one entry action.</p><h2 id="what-the-list-shows" tabindex="-1">What the list shows <a class="header-anchor" href="#what-the-list-shows" aria-label="Permalink to &quot;What the list shows&quot;">​</a></h2><p>The <strong>Record Batches</strong> page can show:</p><ul><li>date</li><li>event</li><li>kingdom</li><li>alliance</li><li>input source</li><li>status</li><li>row count</li><li>last updated time</li></ul><p>From the list, you can open:</p><ul><li>the batch detail</li><li>the related event results</li><li>the related import, when there is one</li></ul><h2 id="what-you-can-do-inside-a-batch" tabindex="-1">What you can do inside a batch <a class="header-anchor" href="#what-you-can-do-inside-a-batch" aria-label="Permalink to &quot;What you can do inside a batch&quot;">​</a></h2><p>On a batch detail page, authorized users can:</p><ul><li>review all saved rows together</li><li>edit score, status, position, review flags, and notes</li><li>add a row</li><li>delete a row</li></ul><p>This is the best page when you care about one saved batch rather than one whole instance.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./manual-input.html">Enter Results Manually</a></li><li><a href="./instance-detail.html">Work Inside an Instance</a></li><li><a href="./../imports/history-and-changes.html">Import History &amp; Change Tracking</a></li></ul>',18)])])}const m=a(i,[["render",l]]);export{p as __pageData,m as default};
